('spanish:p-2-tricky-letters-ll-ch-j-h-r-v:match:003e86a1', 'spanish', 'spanish:p-2-tricky-letters-ll-ch-j-h-r-v', 'P.2 Tricky Letters: ll, ch, ñ, j, h, r, v', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “beber”?", "options": ["throaty /x/ sound (ojo, naranja)", "‘but’ — single-tap r", "‘to drink’ — same soft ‘b’ sound as v", "the name of the letter v — borrows the ‘b’ sound"]}'::jsonb, '{"answer": 2, "explain": "“beber” means: ‘to drink’ — same soft ‘b’ sound as v"}'::jsonb),
('spanish:p-2-tricky-letters-ll-ch-j-h-r-v:match:6975fc26', 'spanish', 'spanish:p-2-tricky-letters-ll-ch-j-h-r-v', 'P.2 Tricky Letters: ll, ch, ñ, j, h, r, v', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “uve”?", "options": ["the ‘ny’ glide (mañana, cumpleaños)", "‘green’ — soft ‘b’ sound, not an English v", "‘dog’ — strongly rolled rr", "the name of the letter v — borrows the ‘b’ sound"]}'::jsonb, '{"answer": 3, "explain": "“uve” means: the name of the letter v — borrows the ‘b’ sound"}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:d11ecc2e', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"la ciudad\" data-listen></span><br>Listen. What is being said?", "options": ["the city", "the nation", "the day", "the problem"]}'::jsonb, '{"answer": 0, "explain": "‘la ciudad’ = the city. The traps are all other gender-rule nouns from this topic."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:e733f48e', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"el mapa\" data-listen></span><br>Listen. Which word did you hear?", "options": ["el mapa", "la mapa", "el mano", "la mano"]}'::jsonb, '{"answer": 0, "explain": "mapa is a masculine exception → el mapa. The traps swap the gender or swap in a different exception word (mano)."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:a9acbdd5', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"el problema\" data-listen></span><br>Listen and choose the correct English meaning.", "options": ["the problem", "the climate", "the day", "the map"]}'::jsonb, '{"answer": 0, "explain": "‘el problema’ = the problem. All four options are genuine masculine -a exceptions, so you must listen carefully."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:91cf9fe4', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "Choose the correct article: ___ problema es difícil.", "options": ["El", "La", "Los", "Las"]}'::jsonb, '{"answer": 0, "explain": "problema is a masculine exception ending in -a → El problema. La/Los/Las are all wrong gender or number."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:14acd56b', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "Choose the correct plural of ''el lápiz''.", "options": ["los lápices", "los lápizes", "las lápices", "los lápiz"]}'::jsonb, '{"answer": 0, "explain": "z changes to c before -es: el lápiz → los lápices. Trap B keeps the z; C changes the gender; D forgets the plural ending."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:6f979aaf', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "How do you say ''a house'' in Spanish?", "options": ["una casa", "un casa", "unos casa", "unas casas"]}'::jsonb, '{"answer": 0, "explain": "casa is feminine singular → una casa. B uses the masculine article; C and D wrongly make it plural."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:d4efdec6', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "Which is the correct way to say ''to the gym''?", "options": ["al gimnasio", "a el gimnasio", "del gimnasio", "a la gimnasio"]}'::jsonb, '{"answer": 0, "explain": "a + el must contract to al. B leaves it uncontracted; C confuses al with del (of/from); D mixes a with the wrong gender article."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:0be1efbf', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "Which of these nouns is feminine?", "options": ["la nación", "el día", "el mapa", "el problema"]}'::jsonb, '{"answer": 0, "explain": "nación ends in -ción, so it is always feminine. The other three are classic masculine exceptions ending in -a."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:535f45ce', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "Choose the correct plural: ''una ciudad'' → ___", "options": ["unas ciudades", "unos ciudades", "unas ciudad", "un ciudades"]}'::jsonb, '{"answer": 0, "explain": "ciudad is feminine → unas; the consonant ending adds -es → unas ciudades."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:mcq:8937efe0', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'mcq', 'mcq', 1, '{"question": "Which phrase correctly means ''the boy''s book'' (el libro ___ chico)?", "options": ["del", "de el", "de la", "al"]}'::jsonb, '{"answer": 0, "explain": "de + el must contract to del. B leaves it uncontracted; C uses the wrong gender; D confuses del with al (to the)."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:c714a067', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "All nouns ending in -o are masculine, with no exceptions."}'::jsonb, '{"answer": false, "explain": "la mano is a common exception — it ends in -o but is feminine."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:ff7c4eaa', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "''el problema'' is masculine even though it ends in -a."}'::jsonb, '{"answer": true, "explain": "el problema, el día, el mapa and el clima are exceptions ending in -a."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:30576f0d', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "Nouns ending in -ción, -sión or -dad are always feminine."}'::jsonb, '{"answer": true, "explain": "This rule has no exceptions — la nación, la televisión, la ciudad."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:4643e2e8', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "The plural of ''el lápiz'' is ''los lápizes''."}'::jsonb, '{"answer": false, "explain": "z changes to c before -es: the correct plural is los lápices."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:bc4dc406', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "''un'' and ''una'' both mean ''the''."}'::jsonb, '{"answer": false, "explain": "un/una mean ''a/an''; el/la mean ''the''."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:30c89fe3', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "''a + el'' must contract to ''al''."}'::jsonb, '{"answer": true, "explain": "Spanish never writes ''a el'' — it always contracts to al."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:7b13efdb', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "''de la casa'' should contract to ''dela casa''."}'::jsonb, '{"answer": false, "explain": "Only de+el (→del) and a+el (→al) contract; de+la never changes."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tf:7f8975d1', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tf', 'tf', 1, '{"question": "''unas ciudades'' means ''some cities''."}'::jsonb, '{"answer": true, "explain": "unas = some (fem. plural); ciudades = cities."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:learn:fe253e45', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'learn', 'mcq', 1, '{"readingTitle": "What is grammatical gender?", "reading": "<p>Every Spanish noun (naming word) is either <strong>masculine</strong> or <strong>feminine</strong> — this is its <em>gender</em>. Gender decides which word for \"the\" or \"a\" you use in front of it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el chico\">el chico</span></td><td>the boy (masc.)</td><td><span data-say=\"la chica\">la chica</span></td><td>the girl (fem.)</td></tr>\n              <tr><td><span data-say=\"el libro\">el libro</span></td><td>the book (masc.)</td><td><span data-say=\"la mesa\">la mesa</span></td><td>the table (fem.)</td></tr>\n            </table>\n            <p>Gender is not about meaning — <span data-say=\"la mesa\">la mesa</span> (table) is grammatically feminine even though a table has no gender in real life. You simply have to learn <strong>el</strong> or <strong>la</strong> with every new noun as you meet it.</p>", "question": "What does ''gender'' mean for a Spanish noun?", "options": ["it is masculine or feminine, shown by el or la before it", "it is singular or plural, shown by adding an -s or -es ending", "it is a person, a place or a thing in the sentence", "it carries a written accent on the final vowel"]}'::jsonb, '{"answer": 0, "explain": "Gender = masculine or feminine; it decides el/la, un/una and adjective endings, not number or word type."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:learn:137a83a6', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'learn', 'mcq', 1, '{"readingTitle": "How do I know if a noun is masculine or feminine?", "reading": "<p>The general rule: nouns ending in <strong>-o</strong> are usually masculine, and nouns ending in <strong>-a</strong> are usually feminine.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el coche\">el coche</span></td><td>the car</td><td><span data-say=\"la casa\">la casa</span></td><td>the house</td></tr>\n              <tr><td><span data-say=\"el gato\">el gato</span></td><td>the cat</td><td><span data-say=\"la ventana\">la ventana</span></td><td>the window</td></tr>\n            </table>\n            <p>But watch these common <strong>exceptions</strong> — words ending in -a that are actually masculine (many come from Greek):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el día\">el día</span></td><td>the day</td><td><span data-say=\"el mapa\">el mapa</span></td><td>the map</td></tr>\n              <tr><td><span data-say=\"el problema\">el problema</span></td><td>the problem</td><td><span data-say=\"el clima\">el clima</span></td><td>the climate</td></tr>\n            </table>\n            <p>And one very common word ending in -o that is feminine instead: <span data-say=\"la mano\">la mano</span> (the hand).</p>\n            <p>Example: <span data-say=\"El problema es que la mano me duele.\">El problema es que la mano me duele.</span> — The problem is that my hand hurts.</p>", "question": "Which of these words is masculine, even though it ends in -a?", "options": ["el problema", "la habitación", "la ventana", "la mesa"]}'::jsonb, '{"answer": 0, "explain": "el problema, el día, el mapa and el clima end in -a but are masculine — common exceptions to learn by heart."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:learn:36fdf00b', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'learn', 'mcq', 1, '{"readingTitle": "Nouns ending in -ción, -sión or -dad", "reading": "<p>Another reliable rule: nouns ending in <strong>-ción</strong>, <strong>-sión</strong> or <strong>-dad</strong> are always feminine — this rule has no exceptions.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la nación\">la nación</span></td><td>the nation</td><td><span data-say=\"la información\">la información</span></td><td>the information</td></tr>\n              <tr><td><span data-say=\"la televisión\">la televisión</span></td><td>the television</td><td><span data-say=\"la ciudad\">la ciudad</span></td><td>the city</td></tr>\n            </table>\n            <p>This is one of the most useful rules in GCSE Spanish because it always works — memorise it and you can always get the article right for these endings.</p>\n            <p>Example: <span data-say=\"La ciudad tiene mucha información sobre la nación.\">La ciudad tiene mucha información sobre la nación.</span></p>", "question": "What gender are nouns ending in -ción, -sión or -dad?", "options": ["always feminine, with no exceptions to learn", "always masculine, unless the word is very short", "masculine in the singular but feminine in the plural", "it depends on the very first letter of the word"]}'::jsonb, '{"answer": 0, "explain": "-ción/-sión/-dad nouns are always feminine — one of the few gender rules with no exceptions."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:learn:7f63151f', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'learn', 'mcq', 1, '{"readingTitle": "Definite articles: el, la, los, las", "reading": "<p>\"The\" changes depending on gender AND number (singular/plural):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>masc. singular</td><td><span data-say=\"el libro\">el libro</span></td><td>masc. plural</td><td><span data-say=\"los libros\">los libros</span></td></tr>\n              <tr><td>fem. singular</td><td><span data-say=\"la mesa\">la mesa</span></td><td>fem. plural</td><td><span data-say=\"las mesas\">las mesas</span></td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> One tricky rule: a feminine singular noun that starts with a stressed <strong>a-</strong> sound takes <strong>el</strong> instead of <strong>la</strong>, just to avoid two a-sounds clashing — but it stays feminine, so the plural is still <strong>las</strong>: <span data-say=\"el agua\">el agua</span> (fem.) → <span data-say=\"las aguas\">las aguas</span>.</p>", "question": "What is the plural of ''la ciudad''?", "options": ["las ciudades", "los ciudades", "las ciudad", "el ciudades"]}'::jsonb, '{"answer": 0, "explain": "la → las for feminine plural, and ciudad adds -es because it ends in a consonant → las ciudades."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:learn:185fde9f', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'learn', 'mcq', 1, '{"readingTitle": "Indefinite articles: un, una, unos, unas", "reading": "<p>\"A / an\" is <strong>un</strong> (masc.) or <strong>una</strong> (fem.). The plural forms <strong>unos / unas</strong> mean \"some\":</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"un libro\">un libro</span></td><td>a book</td><td><span data-say=\"unos libros\">unos libros</span></td><td>some books</td></tr>\n              <tr><td><span data-say=\"una mesa\">una mesa</span></td><td>a table</td><td><span data-say=\"unas mesas\">unas mesas</span></td><td>some tables</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Tengo un problema y unas preguntas.\">Tengo un problema y unas preguntas.</span> — I have a problem and some questions.</p>", "question": "How do you say ''some cities'' in Spanish?", "options": ["unas ciudades", "unos ciudades", "unas ciudad", "un ciudades"]}'::jsonb, '{"answer": 0, "explain": "ciudad is feminine → unas; the plural adds -es because it ends in a consonant → unas ciudades."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:learn:999b207b', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'learn', 'mcq', 1, '{"readingTitle": "Forming plurals + the contractions del and al", "reading": "<p>Plural rules for nouns:</p>\n            <ul>\n              <li>ends in a vowel → add <strong>-s</strong>: <span data-say=\"el coche\">el coche</span> → <span data-say=\"los coches\">los coches</span></li>\n              <li>ends in a consonant → add <strong>-es</strong>: <span data-say=\"el profesor\">el profesor</span> → <span data-say=\"los profesores\">los profesores</span></li>\n              <li>ends in <strong>-z</strong> → change to <strong>-c</strong> and add <strong>-es</strong>: <span data-say=\"el lápiz\">el lápiz</span> → <span data-say=\"los lápices\">los lápices</span>; <span data-say=\"la luz\">la luz</span> → <span data-say=\"las luces\">las luces</span></li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> Two contractions are compulsory in Spanish: <strong>de + el = del</strong>, and <strong>a + el = al</strong> (Spanish never writes <em>de el</em> or <em>a el</em>).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"del colegio\">del colegio</span></td><td>of / from the school</td><td><span data-say=\"al gimnasio\">al gimnasio</span></td><td>to the gym</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Voy al gimnasio después del colegio.\">Voy al gimnasio después del colegio.</span> — I go to the gym after school.</p>", "question": "Which sentence uses the contractions correctly?", "options": ["Voy al gimnasio después del colegio.", "Voy a el gimnasio después de el colegio.", "Voy al gimnasio después de el colegio.", "Voy a el gimnasio después del colegio."]}'::jsonb, '{"answer": 0, "explain": "a+el must always contract to al, and de+el must always contract to del — both together, every time."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:misc:183ea5e5', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> la problema</p><p><strong>✅ The correct idea:</strong> el problema</p>", "question": "Why is ''el problema'' correct, not ''la problema''?", "options": ["''problema'' is a masculine exception ending in -a", "''problema'' is only ever used in the plural form", "''la'' is used before every noun that starts with p", "''problema'' takes no article at all in Spanish"]}'::jsonb, '{"answer": 0, "explain": "problema, día, mapa and clima are masculine despite ending in -a."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:misc:90e423b7', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> el mano</p><p><strong>✅ The correct idea:</strong> la mano</p>", "question": "Why is ''la mano'' correct, not ''el mano''?", "options": ["''mano'' is a feminine exception ending in -o", "''mano'' is a masculine noun in every context", "''mano'' takes no article at all in Spanish", "''la'' is used only with plural nouns like manos"]}'::jsonb, '{"answer": 0, "explain": "la mano is one of the few -o nouns that is actually feminine."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:misc:eeef21c1', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> de el chico</p><p><strong>✅ The correct idea:</strong> del chico</p>", "question": "Why must you write ''del chico'', not ''de el chico''?", "options": ["de + el always contracts to del", "de and el can never appear in the same sentence", "''del'' is only ever used with feminine nouns", "''chico'' automatically changes de into del"]}'::jsonb, '{"answer": 0, "explain": "de+el must contract to del — Spanish never writes de el."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:misc:ce7ca95b', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> lápizes</p><p><strong>✅ The correct idea:</strong> lápices</p>", "question": "Why is the plural ''lápices'', not ''lápizes''?", "options": ["z changes to c before adding the plural ending -es", "lápiz never has a plural form in Spanish at all", "you simply add -s after any consonant ending", "the written accent always moves onto the final syllable"]}'::jsonb, '{"answer": 0, "explain": "Nouns ending in -z change z→c before -es: lápiz→lápices, luz→luces."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:misc:c5cbd355', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> el ciudad</p><p><strong>✅ The correct idea:</strong> la ciudad</p>", "question": "Why is ''la ciudad'' correct, not ''el ciudad''?", "options": ["nouns ending in -dad are always feminine", "''ciudad'' is a masculine exception like día or mapa", "''el'' is used before any word with more than two syllables", "ciudad has no fixed gender and either article works"]}'::jsonb, '{"answer": 0, "explain": "-dad nouns are always feminine — la ciudad, la verdad, la libertad."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tips:21aac709', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Listening: gender clues", "reading": "Even when you don''t catch every word, el/la/un/una/los/las tell you the gender and number before the noun arrives. Listen for ''del'' and ''al'' too — they signal ''from/of the'' and ''to the'', and both only ever attach to a masculine noun.", "question": "You hear ''del colegio''. What must the noun ''colegio'' be?", "options": ["masculine, because del can only exist as de + el", "feminine, because del always marks a feminine noun", "plural, because del is a special plural marker", "in the future tense, because del signals ''will''"]}'::jsonb, '{"answer": 0, "explain": "del only exists because de+el contract — colegio must be masculine."}'::jsonb),
('spanish:g-1-nouns-articles-and-gender:tips:9525e5d0', 'spanish', 'spanish:g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 3 — Reading: spotting exceptions", "reading": "Examiners love testing el día, el mapa, el problema, el clima and la mano because they break the -o/-a rule. If a text uses ''el'' before what looks like a feminine-shaped noun, check it isn''t one of these classic exceptions before you answer.", "question": "In a reading text you see ''el mapa''. What should you remember?", "options": ["mapa is a genuine masculine exception, not an error", "this must be a printing mistake somewhere in the exam paper", "mapa is always used in the plural in Spanish", "el is being used here instead of los by mistake"]}'::jsonb, '{"answer": 0, "explain": "el mapa is a genuine masculine exception, not an error."}'::jsonb),
